long long solve(std::vector<long long> prices, std::vector<long long> strategy, long long k) {
    long long max_profit = 0;
    long long original_profit = 0;

    // Calculate the original profit
    for (int i = 0; i < prices.size(); ++i) {
        original_profit += strategy[i] * prices[i];
    }

    // Try to improve the profit by modifying a subarray of length k
    for (int i = 0; i <= static_cast<int>(prices.size()) - k; ++i) {
        // Calculate the profit change if we modify the subarray starting at i
        long long change = 0;

        // Original strategy in the subarray: first k/2 elements are -1, next k/2 are 1
        // After modification: first k/2 elements are 0, next k/2 are 1
        // So we need to subtract the contribution of the original -1s and add the contribution of the 0s
        for (int j = 0; j < k; ++j) {
            if (j < k / 2 && strategy[i + j] == -1) {
                change -= strategy[i + j] * prices[i + j];
            } else if (j >= k / 2 && strategy[i + j] == 1) {
                change += strategy[i + j] * prices[i + j];
            }
        }

        // Update the max_profit
        max_profit = std::max(max_profit, original_profit + change);
    }

    return max_profit;
}
